example.code:
# High-volume cached workload — direct Anthropic, app-level fallback
try:
    return anthropic.messages.create(
        model="claude-opus-4",
        messages=msgs,
        extra_headers={"anthropic-beta": "prompt-caching-2024-07-31"},
    )
except (anthropic.APIStatusError, anthropic.APITimeoutError):
    return openai.chat.completions.create(model="gpt-5", messages=msgs)
